// // This module is designed to decrement its count value on each rising edge of the clock signal (clk). The counter will reset to zero when the reset signal (rst) is asserted. The output is a 4-bit wide register representing the current count value.
module top_module(
   // Inputs
   clk,
   rst,
   // Outputs
   count
   );input clk;
   input rst;
   output reg [3:0] count;

   always @(posedge clk) begin
      if (rst) begin
         count <= 4'b0000;
      end
      else begin
         count <= count + 1;
      end
   end

endmodule
